<script>
const form=document.getElementById('archiveForm'),results=document.getElementById('archiveResults');
const esc=s=>String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
form.addEventListener('submit',async e=>{e.preventDefault();const q=document.getElementById('archiveQuery').value.trim();if(!q)return;results.innerHTML='<div class="result"><h3>Searching…</h3></div>';try{const r=await fetch('/beyond-audio/api/archive-search.php?q='+encodeURIComponent(q));if(!r.ok)throw new Error('Search unavailable');const data=await r.json();results.innerHTML=data.items.length?data.items.map(x=>`<article class="result"><div class="meta">${esc(x.mediatype||'media')} · ${esc(x.year||'')}</div><h3>${esc(x.title)}</h3><p>${esc(x.creator||'Internet Archive contributor')}</p><div class="actions"><a target="_blank" rel="noopener" href="${esc(x.details_url)}">Open item</a>${x.download_url?`<a href="${esc(x.download_url)}">Download source</a>`:''}</div></article>`).join(''):'<div class="result"><h3>No results</h3><p>Try a broader search.</p></div>'}catch(err){results.innerHTML='<div class="result"><h3>Archive temporarily unavailable</h3><p>Please try again later.</p></div>'}});
</script></body></html>
